def solve(weights: Array[Long]): Long = {
  val n = weights.length
  if (n < 2) return 0L

  val pge = Array.fill(n)(-1)
  val stack = scala.collection.mutable.Stack[Int]()

  for (i <- 0 until n) {
    while (stack.nonEmpty && weights(stack.top) <= weights(i)) {
      stack.pop()
    }
    if (stack.nonEmpty) {
      pge(i) = stack.top
    } else {
      pge(i) = -1
    }
    stack.push(i)
  }

  val intervals = for (i <- 0 until n if pge(i) != -1) yield (pge(i), i)
  val sorted = intervals.sortBy(_._2)

  var count = 0L
  var lastEnd = -1

  for ((start, end) <- sorted) {
    if (start > lastEnd) {
      count += 1
      lastEnd = end
    }
  }

  count
}
